let TW=64,TH=32,GW=40,GH=28,T={},NAMES={},PRODUCT=new Set(),ZONES=[],DESKS=[],CHAIR=null,SECS=[],VISITORS=[];
let MEET=[],MEET_T=[],LOUNGE=[],CAFE=[],CAFE_T=[],BLOCK=new Set(),chars=[],byId={},SNAP=null,LOCAL_TASKS=[];
