function fit(){const areas=ZONES.length?ZONES:[{x:0,y:0,w:GW,h:GH}],corners=areas.flatMap(z=>[W2(z.x,z.y),W2(z.x+z.w,z.y),W2(z.x,z.y+z.h),W2(z.x+z.w,z.y+z.h)]);let minX=1e9,maxX=-1e9,minY=1e9,maxY=-1e9;corners.forEach(p=>{minX=Math.min(minX,p.x);maxX=Math.max(maxX,p.x);minY=Math.min(minY,p.y);maxY=Math.max(maxY,p.y+TH);});const mobile=innerWidth<700,left=mobile?0:300,pad=mobile?30:54,top=mobile?255:105,bottom=mobile?36:48,usableW=Math.max(220,innerWidth-left-pad),usableH=Math.max(200,innerHeight-top-bottom);cam.s=Math.max(.32,Math.min(usableW/(maxX-minX||1),usableH/(maxY-minY||1),2));cam.x=left+(innerWidth-left)/2-(minX+maxX)/2*cam.s;cam.y=top+usableH/2-(minY+maxY)/2*cam.s;floorDirty=true;}
