function focusZone(z){const center=W2(z.x+z.w/2,z.y+z.h/2),target=Math.max(.65,Math.min(1.35,innerWidth/(z.w*TW*1.5)));cam.fit=false;const start={...cam},tx=innerWidth/2-center.x*target,ty=innerHeight/2-center.y*target,started=performance.now(),duration=reducedMotion?1:420;function step(now){const t=Math.min(1,(now-started)/duration),ease=1-(1-t)*(1-t);cam.s=start.s+(target-start.s)*ease;cam.x=start.x+(tx-start.x)*ease;cam.y=start.y+(ty-start.y)*ease;if(t<1)requestAnimationFrame(step);}requestAnimationFrame(step);}
