const pointers=new Map();let drag=null,pinch=null;
cv.addEventListener("pointerdown",e=>{cv.setPointerCapture?.(e.pointerId);pointers.set(e.pointerId,{x:e.clientX,y:e.clientY});if(pointers.size===1)drag={id:e.pointerId,x:e.clientX,y:e.clientY,lastX:e.clientX,lastY:e.clientY,cx:cam.x,cy:cam.y,moved:false};else if(pointers.size===2){const [a,b]=[...pointers.values()];pinch={distance:Math.hypot(a.x-b.x,a.y-b.y),scale:cam.s,midX:(a.x+b.x)/2,midY:(a.y+b.y)/2,cx:cam.x,cy:cam.y};drag=null;}cam.fit=false;});
addEventListener("pointermove",e=>{if(pointers.has(e.pointerId))pointers.set(e.pointerId,{x:e.clientX,y:e.clientY});if(pointers.size===2&&pinch){const[a,b]=[...pointers.values()],distance=Math.hypot(a.x-b.x,a.y-b.y),f=distance/pinch.distance,scale=Math.max(.32,Math.min(pinch.scale*f,3)),midX=(a.x+b.x)/2,midY=(a.y+b.y)/2;cam.x=midX-(pinch.midX-pinch.cx)*(scale/pinch.scale);cam.y=midY-(pinch.midY-pinch.cy)*(scale/pinch.scale);cam.s=scale;return;}if(drag&&drag.id===e.pointerId){drag.lastX=e.clientX;drag.lastY=e.clientY;drag.moved=drag.moved||Math.hypot(e.clientX-drag.x,e.clientY-drag.y)>5;if(drag.moved){cam.x=drag.cx+e.clientX-drag.x;cam.y=drag.cy+e.clientY-drag.y;}}else if(!pointers.size){const tile=screenToTile(e.clientX,e.clientY);hoverChar=chars.reduce((best,ch)=>{const p=SC(ch.cx,ch.cy),d=Math.hypot(p.x-e.clientX,p.y+TH/2*cam.s-e.clientY);return d<(best?.d??34)?{ch,d}:best;},null)?.ch||null;hoverZone=ZONES.find(z=>tile.c>=z.x&&tile.c<z.x+z.w&&tile.r>=z.y&&tile.r<z.y+z.h)||null;}});
